import{_ as e,o as a,c as n,a3 as r}from"./chunks/framework.BveOjhN0.js";const m=JSON.parse('{"title":"Central Application Settings — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Central Application Settings — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/central-settings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Central Application Settings — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/central-settings"}]]},"headers":[],"relativePath":"user-guide/central-settings.md","filePath":"user-guide/central-settings.md","lastUpdated":1784231883000}'),o={name:"user-guide/central-settings.md"};function i(s,t,l,d,c,g){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="central-application-settings-—-user-guide" tabindex="-1">Central Application Settings — User Guide <a class="header-anchor" href="#central-application-settings-—-user-guide" aria-label="Permalink to &quot;Central Application Settings — User Guide&quot;">​</a></h1><p>Central admins configure platform identity and behavior under <strong>Settings</strong> (not Billing).</p><h2 id="tabs" tabindex="-1">Tabs <a class="header-anchor" href="#tabs" aria-label="Permalink to &quot;Tabs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tab</th><th>What to set</th></tr></thead><tbody><tr><td><strong>General</strong></td><td><strong>Application Name</strong> — browser title, sidebar, auth screens. <strong>Company Name</strong> — copyrights and email salutations only. Timezone / Locale / Currency (searchable). Registration enabled.</td></tr><tr><td><strong>Localization</strong></td><td>Date format + 12/24-hour time. Tables and timelines across Central use these formats.</td></tr><tr><td><strong>Mail</strong></td><td>SMTP driver/host/port/credentials, encryption, From name/address. Use <strong>Send test</strong> after saving. Leave password blank to keep the existing secret.</td></tr><tr><td><strong>Branding</strong></td><td>Button color (primary buttons), support email (shown on maintenance/registration-closed and tenant emails), logo + favicon uploads with preview.</td></tr><tr><td><strong>Security</strong></td><td>Session timeout (minutes), minimum password length, require special character. Applies to Central and Tenant password forms.</td></tr><tr><td><strong>Maintenance</strong></td><td>Tenant Application only. Central stays fully usable so you can turn maintenance off. Optional message + ETA.</td></tr><tr><td><strong>Billing</strong></td><td>Invoice prefix, proration mode, default gateway code, trial / Stripe flags. Gateway secrets are managed under <strong>Billing → Payment Gateways</strong>.</td></tr></tbody></table><h2 id="registration-closed" tabindex="-1">Registration closed <a class="header-anchor" href="#registration-closed" aria-label="Permalink to &quot;Registration closed&quot;">​</a></h2><p>When <strong>Registration enabled</strong> is off:</p><ol><li><code>POST /public/register-workspace</code> returns <code>403</code>.</li><li>Visiting <code>/register</code> shows the dedicated <strong>Registration closed</strong> page (with logo/support/copyright when configured).</li></ol><h2 id="tenant-maintenance" tabindex="-1">Tenant maintenance <a class="header-anchor" href="#tenant-maintenance" aria-label="Permalink to &quot;Tenant maintenance&quot;">​</a></h2><p>When <strong>Tenant maintenance mode</strong> is on:</p><ul><li>Tenant API responses return <code>503</code> with <code>code: maintenance_mode</code>.</li><li>Tenant SPA shows the branded maintenance page.</li><li>Central admin API and UI continue to work.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Change Application Name if you want the product title to update immediately (after save + public bootstrap refresh).</li><li>Use Company Name for legal/copyright wording without renaming the product in the chrome.</li><li>After SMTP changes, always send a test email before relying on invites or password resets.</li></ul>',12)])])}const u=e(o,[["render",i]]);export{m as __pageData,u as default};
